/***********************------全局复制携带网站信息-------************************* */
function addLink() {
  var body_element = document.body;
  var selection;
  var copytext;
  var pagelink;
  selection = window.getSelection();
  if (window.clipboardData) {
    // Internet Explorer
    pagelink = "\r\n\r\n 本文为[梦极客园]的原创文章，遵循 CC 4.0 BY-SA 版权协议，转载请附上原文出处链接及本声明 原文链接: " + document.location.href + "";
    copytext = selection + pagelink;
    window.clipboardData.setData("Text", copytext);
    return false;
  } else {
    pagelink = " 本文为[梦极客园]的原创文章，遵循 CC 4.0 BY-SA 版权协议，转载请附上原文出处链接及本声明 原文链接: " + document.location.href + "";
    copytext = selection + pagelink;
    var newdiv = document.createElement('div');
    newdiv.style.position = 'absolute';
    newdiv.style.left = '-99999px';
    body_element.appendChild(newdiv);
    newdiv.innerHTML = copytext;
    selection.selectAllChildren(newdiv);
    window.setTimeout(function () {
      body_element.removeChild(newdiv);
    }, 0);
  }
}
document.body.oncopy = function () {
  //swal("复制成功！", "若要转载请务必保留原文链接，申明来源，谢谢合作！By:梦极客园","success");
  addLink();
