};

/****************************-----鼠标特效-----*******************************/
var a_idx = 0;
document.addEventListener('onreadytstatechange', function ($) {
  document.body.addEventListener("onclick", function (e) {
    var a = new Array("三民主义", "民族", "民权", "民生");
    var $i = $("<span/>").text(a[a_idx]);
    a_idx = (a_idx + 1) % a.length;
    var x = e.pageX,
      y = e.pageY;
    $i.css({
      "z-index": 9999999,
      "top": y - 20,
      "left": x,
      "position": "absolute",
      "font-weight": "bold",
      "color": "#ff6651"
    });
    $("body").append($i);
    $i.animate({
      "top": y - 180,
      "opacity": 0
    }, 1500, function () {
      $i.remove();
    });
  });
});

